using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
const int N=1e5+5;
int Z;
struct ismall
{
	int t,b,h;
};
struct ibig
{
	int t,b;
};
vector<ismall> a1;
vector<ibig> a2;
bool cmp1(ismall x,ismall y)
{
	return x.h>y.h;
}
bool cmp2(ibig x,ibig y)
{
	return x.t<y.t;
}
signed main(void)
{
	cin>>Z;
	while(Z--)
	{
		a1.clear();
		a2.clear();
		int n,T;
		bool sf=0;
		cin>>n>>T;
		FOR(i,1,n)
		{
			int x,y;
			cin>>x>>y;
			if(y<0)
			{
				ismall s;
				s.t=x,s.b=y,s.h=x+y;
				a1.push_back(s);
			}
			else
			{
				ibig s;
				s.t=x,s.b=y;
				a2.push_back(s);
			}
		}
		sort(a1.begin(),a1.end(),cmp1);
		sort(a2.begin(),a2.end(),cmp2);
		for(int i=0;i<a2.size();++i)
		{
			if(T>a2[i].t)
			{
				T+=a2[i].b;
			}
			else
			{
				sf=1;
				break;
			}
		}
		for(int i=0;i<a1.size();++i)
		{
			if(T>a1[i].t)
			{
				T+=a1[i].b;
			}
			else
			{
				sf=1;
				break;
			}
			if(T<=0)
			{
				sf=1;
				break;
			}
		}
		if(!sf)
		{
			puts("+1s");
		}
		else
		{
			puts("-1s");
		}
	} 
	return false;
}
